mapper.select:
SELECT RPT_GJDT AS CODE, TO_CHAR(TO_DATE(RPT_GJDT,'YYYYMMDD'),'YYYY-MM-DD') AS NAME FROM JRBA_RPT_BAS_M WHERE 1=1
AND RPT_GJDT != #{filterComboVal,jdbcType=VARCHAR}
GROUP BY RPT_GJDT ORDER BY CASE WHEN RPT_GJDT ='99991231' THEN 1 ELSE 0 END, RPT_GJDT DESC

SELECT RPT_GJDT AS CODE , TO_CHAR(TO_DATE(RPT_GJDT,'YYYYMMDD'),'YYYY-MM-DD') AS NAME FROM JRBA_RPT_BAS_M WHERE 1=1
AND RPT_GJDT != #{filterComboVal,jdbcType=VARCHAR}
GROUP BY RPT_GJDT UNION ALL SELECT '99991231' AS CODE , '초기적재데이터' AS NAME FROM DUAL WHERE NOT EXISTS ( SELECT 1 FROM JRBA_RPT_BAS_M ) ORDER BY CODE DESC

SELECT COUNT(*) AS CNT
FROM JRBA_RPT_BAS_M A
WHERE A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

mapper.update:
UPDATE JRBA_RPT_BAS_M
   SET BT_BAS_DT = #{DATA_BAS_DT, jdbcType=VARCHAR}
 WHERE RPT_GJDT=#{RPT_GJDT, jdbcType=VARCHAR}

UPDATE JRBA_RPT_BAS_M
   SET BT_JOB_ENDT = ''		-- 자동지표 수행일자를 NULL로 초기화
 WHERE RPT_GJDT=#{RPT_GJDT, jdbcType=VARCHAR}

UPDATE JRBA_JIPYO_M SET
	MNG_BRNO 		= #{MNG_BRNO,jdbcType=VARCHAR}
WHERE RPT_GJDT 		= #{RPT_GJDT, jdbcType=VARCHAR}
	AND JIPYO_IDX 		= #{JIPYO_IDX, jdbcType=VARCHAR}

mapper.select:
SELECT NVL(JIPYO_FIX_YN, 0) JIPYO_FIX_YN
FROM JRBA_RPT_BAS_M
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

mapper.update:
UPDATE JRBA_RPT_BAS_M
SET JIPYO_FIX_YN= 1,
	JIPYO_FIX_DT = TO_CHAR(SYSDATE,'YYYYMMDD'),
	JIPYO_FIX_JKW_NO = #{CHG_OP_JKW_NO}
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

UPDATE JRBA_RPT_BAS_M
SET JIPYO_FIX_YN= 0,
	JIPYO_FIX_DT = TO_CHAR(SYSDATE,'YYYYMMDD'),
	JIPYO_FIX_JKW_NO = #{CHG_OP_JKW_NO}
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

mapper.delete:
DELETE FROM JRBA_JIPYO_M
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
	AND JIPYO_IDX = #{JIPYO_IDX, jdbcType=VARCHAR}

mapper.select:
SELECT JIPYO_IDX
FROM JRBA_JIPYO_V
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
	AND JIPYO_IDX = #{JIPYO_IDX, jdbcType=VARCHAR}

SELECT A.JIPYO_IDX --지표번호 ,A.JIPYO_NM --위험지표명 ,A.INP_ITEM --입력항목 ,A.VALT_G --평가구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A007' AND DTL_CD=A.VALT_G) AS VALT_G_NM --평가구분명 ,A.INP_UNIT_C --입력단위코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A012' AND DTL_CD=A.INP_UNIT_C) AS INP_UNIT_C_NM --입력단위명 ,A.ALLT_PNT --배점 ,A.IN_V_TP_C --입력값타입('A008', N:숫자, C:코드, T:텍스트) ,B.IN_V --입력값 ,(CASE WHEN C.USYN = 1 THEN '' WHEN A.JIPYO_C = 'I' THEN '' WHEN A.JIPYO_C = 'O' AND A.VALT_G IN ('1', '4') AND B.IN_V IS NOT NULL THEN RTRIM(TO_CHAR(B.RPT_PNT, 'FM90.99'),'.') WHEN A.JIPYO_C = 'O' AND A.VALT_G ='2' AND B.MAX_IN_V > 0 THEN RTRIM(TO_CHAR(B.RPT_PNT, 'FM90.99'),'.') ELSE '' END ) AS RPT_PNT --지표점수 ,CASE WHEN NVL(B.ATTCH_FILE_NO, 0) = 0 THEN 'N' ELSE 'Y' END AS ATTCH_FILE_YN /* 증빙파일 */ ,B.ATTCH_FILE_NO /* 첨부파일번호 */ ,NVL(B.ITEM_S_C, '0') AS ITEM_S_C --항목상태 HIDDEN ('A010', 0:미확정, 1:저장, 2:확정) ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A010' AND DTL_CD=NVL(B.ITEM_S_C,0)) AS ITEM_S_C_NM --항목상태명 ,A.CAL_FRML --산출식 ,TRIM(A.CAL_METH) AS CAL_METH --산출방법 ,A.JIPYO_C --위험구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A001' AND DTL_CD=A.JIPYO_C) AS JIPYO_C_NM --위험구분코드명 ,A.RSK_CATG --카테고리코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A004' AND DTL_CD=A.RSK_CATG) --//고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A002' AND DTL_CD=A.RSK_CATG) --//운영위험인 경우 END AS RSK_CATG_NM --위험구분코드명 ,A.RSK_FAC --항목코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A005' AND DTL_CD=A.RSK_FAC) --//고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A003' AND DTL_CD=A.RSK_FAC) --//운영위험인 경우 END AS RSK_FAC_NM --위험구분코드명 ,A.CHG_DT --변경일 ,A.CHG_OP_JKW_NO --변경자 ,CASE WHEN IN_V_TP_C='C' --입력값이 '코드' THEN (SELECT REGEXP_REPLACE( LISTAGG (DTL_CD, '##')WITHIN GROUP (ORDER BY DTL_CD)||'@@'||LISTAGG ('['||DTL_CD||'] '||DTL_NM, '##')WITHIN GROUP (ORDER BY DTL_CD), '([^,]+)(,\1)+', '\1') FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I) END AS CD_LST --입력값타입이 코드인경우 사용될 코드리스트 ,NVL(B.MAX_IN_V,0) AS MAX_IN_V ,A.CNCT_JIPYO_C_I /* 연결지표코드정보 */ ,NVL(CASE WHEN IN_V_TP_C='C' --입력값이 '코드' THEN ( SELECT '('||DTL_CD||') '||DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.JIPYO_ID AND DTL_CD=(SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR}) ) ELSE ( SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR} ) END, '-') AS LAST_IN_V --직전기준보고일 데이터 /* 2025.07 비고내용 제거 */ -- ,DECODE(TRIM(B.BIGO_CTNT), '', 'N', 'Y') AS BIGO_CTNT_F -- ,B.BIGO_CTNT ,CASE WHEN USYN = 1 THEN 'Y' WHEN USYN = 0 THEN 'N' END NA_YN -- 해당없음 여부 FROM JRBA_JIPYO_M A ,JRBA_JIPYO_V B ,(SELECT * FROM JRBA_DTL_C WHERE GRP_CD = 'A999') C WHERE A.RPT_GJDT = B.RPT_GJDT(+) AND A.JIPYO_IDX = B.JIPYO_IDX(+) AND A.JIPYO_USYN = '1' --지표사용여부 (0:부, 1:여) AND A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR} AND A.RPT_GJDT=C.RPT_GJDT(+) AND SUBSTR(A.JIPYO_IDX,1,10) = C.DTL_CD(+)
AND A.JIPYO_IDX = #{CHECK_JIPYO_IDX, jdbcType=VARCHAR} --지표번호
AND A.JIPYO_IDX LIKE '%' || #{JIPYO_IDX, jdbcType=VARCHAR} || '%' --지표번호
AND A.JIPYO_NM LIKE '%' || #{JIPYO_NM, jdbcType=VARCHAR} || '%' --지표명
AND A.JIPYO_C = #{JIPYO_C, jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR}
AND A.VALT_G = #{VALT_G, jdbcType=VARCHAR}
AND A.JIPYO_IDX NOT IN (SELECT JIPYO_IDX FROM JRBA_JIPYO_V WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR})
AND B.ITEM_S_C = #{ITEM_S_C, jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO, jdbcType=VARCHAR}
AND A.IN_METH_C = #{IN_METH_C, jdbcType=VARCHAR} -- 입력방식
ORDER BY A.JIPYO_IDX

SELECT A.JIPYO_IDX --지표번호 ,A.JIPYO_NM --위험지표명 ,A.INP_ITEM --입력항목 ,A.VALT_G --평가구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A007' AND DTL_CD=A.VALT_G) AS VALT_G_NM --평가구분명 ,A.INP_UNIT_C --입력단위코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A012' AND DTL_CD=A.INP_UNIT_C) AS INP_UNIT_C_NM --입력단위명 ,A.ALLT_PNT --배점 ,A.IN_V_TP_C --입력값타입('A008', N:숫자, C:코드, T:텍스트) ,B.IN_V ,NVL(CASE WHEN IN_V_TP_C='C' --입력값이 '코드' THEN ( SELECT '['||DTL_CD||'] '||DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I AND DTL_CD=B.IN_V ) ELSE RTRIM(TO_CHAR(TRUNC(B.IN_V,2),'FM999,999,999,999,999,990.99'), '.') END, '-') AS A_IN_V ,(CASE WHEN A.JIPYO_C = 'I' THEN '' WHEN A.JIPYO_C = 'O' AND A.VALT_G IN ('1', '4') AND B.IN_V IS NOT NULL THEN RTRIM(TO_CHAR(B.RPT_PNT, 'FM90.99'),'.') WHEN A.JIPYO_C = 'O' AND A.VALT_G ='2' AND B.MAX_IN_V > 0 THEN RTRIM(TO_CHAR(B.RPT_PNT, 'FM90.99'),'.') ELSE '' END ) AS RPT_PNT --지표점수 ,CASE WHEN NVL(B.ATTCH_FILE_NO, 0) = 0 THEN 'N' ELSE 'Y' END AS ATTCH_FILE_YN /* 증빙파일 */ ,B.ATTCH_FILE_NO /* 첨부파일번호 */ ,NVL(B.ITEM_S_C, '0') AS ITEM_S_C --항목상태 HIDDEN ('A010', 0:미확정, 1:저장, 2:확정) ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A010' AND DTL_CD=NVL(B.ITEM_S_C,0)) AS ITEM_S_C_NM --항목상태명 ,A.CAL_FRML --산출식 ,A.CAL_METH --산출방법 ,A.JIPYO_C --위험구분코드 HIDDEN ,(SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A001' AND DTL_CD=A.JIPYO_C) AS JIPYO_C_NM --위험구분코드명 ,A.RSK_CATG --카테고리코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A004' AND DTL_CD=A.RSK_CATG) --//고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A002' AND DTL_CD=A.RSK_CATG) --//운영위험인 경우 END AS RSK_CATG_NM --위험구분코드명 ,A.RSK_FAC --항목코드 HIDDEN ,CASE WHEN A.JIPYO_C='I' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A005' AND DTL_CD=A.RSK_FAC) --//고유위험인 경우 WHEN A.JIPYO_C='O' THEN (SELECT DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD='A003' AND DTL_CD=A.RSK_FAC) --//운영위험인 경우 END AS RSK_FAC_NM --위험구분코드명 ,A.CHG_DT --변경일 ,A.CHG_OP_JKW_NO --변경자 ,CASE WHEN IN_V_TP_C='C' --입력값이 '코드' THEN (SELECT REGEXP_REPLACE( LISTAGG (DTL_CD, '##')WITHIN GROUP (ORDER BY DTL_CD)||'@@'||LISTAGG ('['||DTL_CD||'] '||DTL_NM, '##')WITHIN GROUP (ORDER BY DTL_CD), '([^,]+)(,\1)+', '\1') FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I) END AS CD_LST --입력값타입이 코드인경우 사용될 코드리스트 ,NVL(B.MAX_IN_V,0) AS MAX_IN_V ,A.CNCT_JIPYO_C_I /* 연결지표코드정보 */ ,NVL(CASE WHEN IN_V_TP_C='C' --입력값이 '코드' THEN ( SELECT '['||DTL_CD||'] '||DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT=A.RPT_GJDT AND GRP_CD=A.CNCT_JIPYO_C_I AND DTL_CD=(SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR}) ) ELSE ( SELECT IN_V FROM JRBA_JIPYO_V WHERE JIPYO_IDX=A.JIPYO_IDX AND RPT_GJDT=#{LAST_RPT_GJDT, jdbcType=VARCHAR} ) END, '-') AS LAST_IN_V --직전기준보고일 데이터 -- 비고내용 -- ,DECODE(TRIM(B.BIGO_CTNT), '', 'N', 'Y') AS BIGO_CTNT_F -- ,B.BIGO_CTNT FROM JRBA_JIPYO_M A ,JRBA_JIPYO_V B WHERE A.RPT_GJDT = B.RPT_GJDT(+) AND A.JIPYO_IDX = B.JIPYO_IDX(+) AND A.JIPYO_USYN = '1' --지표사용여부 (0:부, 1:여) AND A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
AND A.JIPYO_IDX = #{CHECK_JIPYO_IDX, jdbcType=VARCHAR} --지표번호
AND A.JIPYO_IDX LIKE '%' || #{JIPYO_IDX, jdbcType=VARCHAR} || '%' --지표번호
AND A.JIPYO_NM LIKE '%' || #{JIPYO_NM, jdbcType=VARCHAR} || '%' --지표명
AND A.JIPYO_C = #{JIPYO_C, jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR}
AND A.VALT_G = #{VALT_G, jdbcType=VARCHAR}
AND A.JIPYO_IDX NOT IN (SELECT JIPYO_IDX FROM JRBA_JIPYO_V WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR})
AND B.ITEM_S_C = #{ITEM_S_C, jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO, jdbcType=VARCHAR}
AND A.IN_METH_C = #{IN_METH_C, jdbcType=VARCHAR} -- 입력방식
ORDER BY A.JIPYO_IDX

mapper.update:
UPDATE JRBA_RPT_BAS_M SET
	BT_JOB_ENDT = TO_CHAR(SYSDATE, 'YYYYMMDD')
WHERE RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}

MERGE INTO JRBA_JIPYO_V A
  USING DUAL
  ON ( A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR} AND A.JIPYO_IDX =  #{JIPYO_IDX, jdbcType=VARCHAR} )
WHEN MATCHED THEN
	UPDATE SET
	       IN_V 	 		= #{IN_V, jdbcType=VARCHAR}
           ,RPT_PNT  		= #{RPT_PNT, jdbcType=VARCHAR}
           ,ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
           ,CHG_DT 	 		= TO_CHAR(SYSDATE,'YYYYMMDD')
           ,CHG_TIME 		= TO_CHAR(SYSDATE,'HH24MISS')
           ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
WHEN NOT MATCHED THEN
	INSERT
	    (
	    RPT_GJDT
	    ,JIPYO_IDX
	    ,IN_V
	    ,RPT_PNT
	    ,ITEM_S_C
	    ,DR_DT
	    ,DR_TIME
	    ,DR_OP_JKW_NO
	    ,CHG_DT
	    ,CHG_TIME
	    ,CHG_OP_JKW_NO
	    )
	VALUES
	    (
	    #{RPT_GJDT, jdbcType=VARCHAR}
	    ,#{JIPYO_IDX, jdbcType=VARCHAR}
	    ,#{IN_V, jdbcType=VARCHAR}
	    ,#{RPT_PNT, jdbcType=VARCHAR}
	    ,#{ITEM_S_C, jdbcType=VARCHAR}
	    ,TO_CHAR(SYSDATE,'YYYYMMDD')
	    ,TO_CHAR(SYSDATE,'HH24MISS')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    ,TO_CHAR(SYSDATE,'YYYYMMDD')
	    ,TO_CHAR(SYSDATE,'HH24MISS')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    )

MERGE INTO JRBA_FIU_JIPYO_V A
  USING DUAL
  ON ( A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR} AND A.JIPYO_IDX =  #{JIPYO_IDX, jdbcType=VARCHAR} )
WHEN MATCHED THEN
	UPDATE SET
	       IN_V 	 		= #{IN_V, jdbcType=VARCHAR}
           ,RPT_PNT  		= #{RPT_PNT, jdbcType=VARCHAR}
           ,ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
           ,CHG_DT 	 		= TO_CHAR(SYSDATE,'YYYYMMDD')
           ,CHG_TIME 		= TO_CHAR(SYSDATE,'HH24MISS')
           ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
WHEN NOT MATCHED THEN
	INSERT
	    (
	    RPT_GJDT
	    ,JIPYO_IDX
	    ,IN_V
	    ,RPT_PNT
	    ,ITEM_S_C
	    ,DR_DT
	    ,DR_TIME
	    ,DR_OP_JKW_NO
	    ,CHG_DT
	    ,CHG_TIME
	    ,CHG_OP_JKW_NO
	    )
	VALUES
	    (
	    #{RPT_GJDT, jdbcType=VARCHAR}
	    ,#{JIPYO_IDX, jdbcType=VARCHAR}
	    ,#{IN_V, jdbcType=VARCHAR}
	    ,#{RPT_PNT, jdbcType=VARCHAR}
	    ,#{ITEM_S_C, jdbcType=VARCHAR}
	    ,TO_CHAR(SYSDATE,'YYYYMMDD')
	    ,TO_CHAR(SYSDATE,'HH24MISS')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    ,TO_CHAR(SYSDATE,'YYYYMMDD')
	    ,TO_CHAR(SYSDATE,'HH24MISS')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    )

UPDATE JRBA_JIPYO_V
   SET ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
       ,CHG_DT 			= TO_CHAR(SYSDATE,'YYYYMMDD')
       ,CHG_TIME 		= TO_CHAR(SYSDATE,'HH24MISS')
       ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE RPT_GJDT 		= #{RPT_GJDT, jdbcType=VARCHAR}
   AND JIPYO_IDX 		= #{JIPYO_IDX, jdbcType=VARCHAR}

UPDATE JRBA_FIU_JIPYO_V
   SET ITEM_S_C 		= #{ITEM_S_C, jdbcType=VARCHAR}
       ,CHG_DT 			= TO_CHAR(SYSDATE,'YYYYMMDD')
       ,CHG_TIME 		= TO_CHAR(SYSDATE,'HH24MISS')
       ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE RPT_GJDT 		= #{RPT_GJDT, jdbcType=VARCHAR}
   AND JIPYO_IDX 		= #{JIPYO_IDX, jdbcType=VARCHAR}

mapper.select:
SELECT NVL(MAX(RPT_GJDT),0) AS LAST_RPT_GJDT
  FROM JRBA_RPT_BAS_M
 WHERE RPT_GJDT  != #{RPT_GJDT, jdbcType=VARCHAR}
   AND RPT_GJDT < #{RPT_GJDT, jdbcType=VARCHAR}
 ORDER BY RPT_GJDT DESC

SELECT IN_V
       ,MAX_IN_V
       ,ATTCH_FILE_NO
  FROM JRBA_JIPYO_V
 WHERE RPT_GJDT = #{LAST_RPT_GJDT, jdbcType=VARCHAR}
   AND JIPYO_IDX = #{JIPYO_IDX, jdbcType=VARCHAR}

mapper.update:
MERGE INTO JRBA_JIPYO_V A
  USING DUAL
  ON ( A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR} AND A.JIPYO_IDX =  #{JIPYO_IDX, jdbcType=VARCHAR} )
WHEN MATCHED THEN
	UPDATE SET
	       IN_V				= #{IN_V, jdbcType=VARCHAR}
