mapper.select:
SELECT '0' AS SELECTED ,JIPYOM.RPT_GJDT ,JIPYOM.JIPYO_IDX ,JIPYOM.JIPYO_C ,JIPYOM.RSK_CATG ,JIPYOM.RSK_FAC ,JIPYOM.JIPYO_NM ,JIPYOM.JIPYO_DESC ,JIPYOM.JIPYO_BIGO_CTNT ,JIPYOM.EST_BAS_SCOP ,JIPYOM.CAL_FRML ,JIPYOM.INP_ITEM ,JIPYOM.INP_UNIT_C ,JIPYOM.ANEX_CTNT ,JIPYOM.FRMG_MABD_C ,JIPYOM.VALT_G ,JIPYOM.ALLT_PNT ,JIPYOM.WEGHT ,JIPYOM.BAS_V ,JIPYOM.CAL_METH ,JIPYOM.IN_V_TP_C ,JIPYOM.CNCT_JIPYO_C_I ,JIPYOM.MNG_BRNO ,JIPYOM.IN_METH_C ,JIPYOM.JIPYO_USYN ,JIPYOM.JIPYO_ID ,JIPYOV.IN_V ,(CASE WHEN JIPYOM.JIPYO_C = 'I' THEN '' WHEN JIPYOM.JIPYO_C = 'O' AND JIPYOM.VALT_G IN ('1', '4') THEN RTRIM(TO_CHAR(JIPYOV.RPT_PNT, 'FM90.99'),'.') WHEN JIPYOM.JIPYO_C = 'O' AND JIPYOM.VALT_G ='2' AND JIPYOV.MAX_IN_V > 0 THEN RTRIM(TO_CHAR(JIPYOV.RPT_PNT, 'FM90.99'),'.') ELSE '' END ) RPT_PNT ,JIPYOV.MAX_IN_V ,JIPYOV.DR_DT ,JIPYOV.DR_TIME ,JIPYOV.DR_OP_JKW_NO ,JIPYOV.CHG_DT ,JIPYOV.CHG_TIME ,JIPYOV.CHG_OP_JKW_NO ,JIPYOV.ITEM_S_C ,DRUSER.USER_NM AS DR_OP_JKW_NM ,CHGUSER.USER_NM AS CHG_OP_JKW_NM ,A001.DTL_NM AS JIPYO_C_NM ,A007.DTL_NM AS VALT_G_NM ,NIC41B.DPRT_NM AS DPRT_NM ,BASM.JIPYO_FIX_YN ,BASM.JIPYO_FIX_DT FROM JRBA_JIPYO_M JIPYOM LEFT JOIN JRBA_RPT_BAS_M BASM ON JIPYOM.RPT_GJDT=BASM.RPT_GJDT LEFT JOIN JRBA_JIPYO_V JIPYOV ON (JIPYOM.RPT_GJDT = JIPYOV.RPT_GJDT AND JIPYOM.JIPYO_IDX = JIPYOV.JIPYO_IDX) LEFT JOIN JRBA_DTL_C A001 ON JIPYOM.RPT_GJDT = A001.RPT_GJDT AND A001.GRP_CD = 'A001' AND JIPYOM.JIPYO_C=A001.DTL_CD -- 위험구분 LEFT JOIN JRBA_DTL_C A007 ON JIPYOM.RPT_GJDT = A007.RPT_GJDT AND A007.GRP_CD = 'A007' AND JIPYOM.VALT_G=A007.DTL_CD -- 평가구분 LEFT JOIN C_USER CHGUSER ON JIPYOM.CHG_OP_JKW_NO = CHGUSER.LOGIN_ID LEFT JOIN C_USER DRUSER ON JIPYOM.CHG_OP_JKW_NO = DRUSER.LOGIN_ID LEFT JOIN NIC41B NIC41B ON JIPYOM.MNG_BRNO = NIC41B.DPRT_CD WHERE 1=1 AND JIPYOM.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR} AND JIPYOM.JIPYO_USYN = '1' --사용여부 Y
AND JIPYOM.JIPYO_IDX = #{CHECK_JIPYO_IDX, jdbcType=VARCHAR} --지표번호
AND JIPYOM.JIPYO_IDX LIKE '%' || #{JIPYO_IDX, jdbcType=VARCHAR} || '%' --지표번호
AND JIPYOM.JIPYO_NM LIKE '%' || #{JIPYO_NM, jdbcType=VARCHAR} || '%' --지표명
AND JIPYOM.JIPYO_C = #{JIPYO_C, jdbcType=VARCHAR}
AND JIPYOM.VALT_G = #{VALT_G, jdbcType=VARCHAR}
AND JIPYOM.MNG_BRNO = #{MNG_BRNO, jdbcType=VARCHAR}
ORDER BY JIPYOM.JIPYO_IDX

