mapper.select:
WITH V_GJDT AS ( SELECT MAX(CASE WHEN SNO = 1 THEN BB.RPT_GJDT END) AS RPT_GJDT1 ,MAX(CASE WHEN SNO = 2 THEN BB.RPT_GJDT END) AS RPT_GJDT2 ,MAX(CASE WHEN SNO = 3 THEN BB.RPT_GJDT END) AS RPT_GJDT3 FROM (SELECT RPT_GJDT , ROW_NUMBER() OVER (ORDER BY AA.RPT_GJDT DESC ) AS SNO FROM JRBA_RPT_BAS_M AA
WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR} ) BB WHERE SNO < 4
) , V_SCORE_DIFFERENCE1 AS ( SELECT V.JIPYO_IDX , V.RPT_GJDT , (RTRIM(TO_CHAR(V.RPT_PNT, 'FM90.99'),'.') - (SELECT RTRIM(TO_CHAR(RPT_PNT, 'FM90.99'),'.') FROM JRBA_FIU_JIPYO_V X WHERE X.RPT_GJDT =VG.RPT_GJDT2 AND X.JIPYO_IDX =V.JIPYO_IDX )) AS SCOREDR FROM JRBA_FIU_JIPYO_V V , V_GJDT VG WHERE RPT_GJDT = VG.RPT_GJDT1 ) , V_SCORE_DIFFERENCE2 AS ( SELECT V.JIPYO_IDX , V.RPT_GJDT , (RTRIM(TO_CHAR(V.RPT_PNT, 'FM90.99'),'.') - (SELECT RTRIM(TO_CHAR(RPT_PNT, 'FM90.99'),'.') FROM JRBA_FIU_JIPYO_V X WHERE X.RPT_GJDT =VG.RPT_GJDT3 AND X.JIPYO_IDX =V.JIPYO_IDX )) AS SCOREDR FROM JRBA_FIU_JIPYO_V V , V_GJDT VG WHERE RPT_GJDT = VG.RPT_GJDT2 ) , V_SUMMARY_IN_V AS ( SELECT RPT_GJDT , SUBSTR(JIPYO_IDX,1,10) AS JIPYO_IDX , LISTAGG(IN_V, ' / ') WITHIN GROUP (ORDER BY JIPYO_IDX) AS IN_V FROM JRBA_FIU_JIPYO_V A CROSS JOIN V_GJDT B GROUP BY RPT_GJDT, SUBSTR(JIPYO_IDX,1,10) ) SELECT SUBSTR(A.JIPYO_IDX,1,10) AS JIPYO_IDX , A.RPT_GJDT, A.JIPYO_IDX, A.JIPYO_C, CD01.DTL_NM AS JIPYO_C_NM , A.RSK_CATG, (CASE WHEN A.JIPYO_C = 'O' THEN CD02.DTL_NM ELSE CD04.DTL_NM END) AS RSK_CATG_NM , A.RSK_FAC, (CASE WHEN A.JIPYO_C = 'O' THEN CD03.DTL_NM ELSE CD05.DTL_NM END) AS RSK_FAC_NM , A.JIPYO_NM , RTRIM(TO_CHAR(CURRENT_ROUND.RPT_PNT, 'FM90.99'),'.') AS SCORE1 , RTRIM(TO_CHAR(BF_1ROUND.RPT_PNT, 'FM90.99'),'.') AS SCORE2 , RTRIM(TO_CHAR(BF_2ROUND.RPT_PNT, 'FM90.99'),'.') AS SCORE3 , NVL(NULLIF(CURRENT_ROUND.IN_V,''),'-') AS VAL1 , NVL(NULLIF(BF_1ROUND.IN_V,''),'-') AS VAL2 , NVL(NULLIF(BF_2ROUND.IN_V,''),'-') AS VAL3 , NVL(NULLIF(CURRENT_ROUND.RANK,''),'-') AS RANK1 , NVL(NULLIF(BF_1ROUND.RANK,'') ,'-') AS RANK2 , NVL(NULLIF(BF_2ROUND.RANK,'') ,'-') AS RANK3 , NVL(NULLIF(CURRENT_ROUND.GRP_AVG_PNT,''),'-') AS GRP_AVG_PNT1 , NVL(NULLIF(BF_1ROUND.GRP_AVG_PNT,'') ,'-') AS GRP_AVG_PNT2 , NVL(NULLIF(BF_2ROUND.GRP_AVG_PNT,'') ,'-') AS GRP_AVG_PNT3 , (SELECT RTRIM(TO_CHAR(SCOREDR, 'FM90.99'),'.') FROM V_SCORE_DIFFERENCE1 WHERE JIPYO_IDX = A.JIPYO_IDX) AS SCOREDR1 --(최근회차 - 직전회차) , (SELECT RTRIM(TO_CHAR(SCOREDR, 'FM90.99'),'.') FROM V_SCORE_DIFFERENCE2 WHERE JIPYO_IDX = A.JIPYO_IDX) AS SCOREDR2 --(직전회차 - 전전회차) , A.RPT_GJDT , B.RPT_GJDT1 , B.RPT_GJDT2 , B.RPT_GJDT3 , NVL(D.GYLJ_ID, 0) AS GYLJ_ID /* 결재ID */ , NVL(D.GYLJ_S_C, 0) AS GYLJ_S_C /* 결재상태코드 */ , CASE WHEN NVL(D.GYLJ_S_C, 0) = '3' THEN 'Y' /* 지표결재상태코드(A014) = 3(완료) */ ELSE 'N' END AS FINL_GYLJ_S /* 최종승인여부 */ FROM JRBA_JIPYO_M A INNER JOIN JRBA_FIU_JIPYO_V C ON A.RPT_GJDT = C.RPT_GJDT AND A.JIPYO_IDX = C.JIPYO_IDX LEFT JOIN ( SELECT IA.JIPYO_IDX , (CASE WHEN DT_CD.USYN = 1 THEN '해당없음' WHEN IM.JIPYO_C = 'O' AND IM.IN_V_TP_C = 'C' THEN (SELECT '['||DTL_CD||'] '||DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT = IM.RPT_GJDT AND GRP_CD = IM.CNCT_JIPYO_C_I AND DTL_CD = IA.IN_V) WHEN LENGTH(IA.JIPYO_IDX) = 11 THEN IC.IN_V ELSE IC.IN_V END) AS IN_V , IA.GRP_AVG_PNT , IA.RANK , IA.RPT_PNT , IA.RPT_GJDT FROM JRBA_FIU_JIPYO_V IA INNER JOIN V_GJDT IB ON IA.RPT_GJDT = IB.RPT_GJDT1 INNER JOIN V_SUMMARY_IN_V IC ON IA.RPT_GJDT = IC.RPT_GJDT AND SUBSTR(IA.JIPYO_IDX,1,10) = IC.JIPYO_IDX INNER JOIN JRBA_JIPYO_M IM ON IA.RPT_GJDT = IM.RPT_GJDT AND IA.JIPYO_IDX = IM.JIPYO_IDX LEFT JOIN JRBA_DTL_C DT_CD ON IA.RPT_GJDT = DT_CD.RPT_GJDT AND IA.JIPYO_IDX = DT_CD.DTL_CD AND DT_CD.GRP_CD = 'A999' ) CURRENT_ROUND ON A.JIPYO_IDX = CURRENT_ROUND.JIPYO_IDX LEFT JOIN (SELECT IA.JIPYO_IDX , (CASE WHEN DT_CD.USYN = 1 THEN '해당없음' WHEN IM.JIPYO_C = 'O' AND IM.IN_V_TP_C = 'C' THEN (SELECT '['||DTL_CD||'] '||DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT = IM.RPT_GJDT AND GRP_CD = IM.CNCT_JIPYO_C_I AND DTL_CD = IA.IN_V) WHEN LENGTH(IA.JIPYO_IDX) = 11 THEN IC.IN_V ELSE IC.IN_V END) AS IN_V , IA.GRP_AVG_PNT , IA.RANK , IA.RPT_PNT , IA.RPT_GJDT FROM JRBA_FIU_JIPYO_V IA INNER JOIN V_GJDT IB ON IA.RPT_GJDT = IB.RPT_GJDT2 INNER JOIN V_SUMMARY_IN_V IC ON IA.RPT_GJDT = IC.RPT_GJDT AND SUBSTR(IA.JIPYO_IDX,1,10) = IC.JIPYO_IDX INNER JOIN JRBA_JIPYO_M IM ON IA.RPT_GJDT = IM.RPT_GJDT AND IA.JIPYO_IDX = IM.JIPYO_IDX LEFT JOIN JRBA_DTL_C DT_CD ON IA.RPT_GJDT = DT_CD.RPT_GJDT AND IA.JIPYO_IDX = DT_CD.DTL_CD AND DT_CD.GRP_CD = 'A999' ) BF_1ROUND ON A.JIPYO_IDX = BF_1ROUND.JIPYO_IDX LEFT JOIN (SELECT IA.JIPYO_IDX , (CASE WHEN DT_CD.USYN = 1 THEN '해당없음' WHEN IM.JIPYO_C = 'O' AND IM.IN_V_TP_C = 'C' THEN (SELECT '['||DTL_CD||'] '||DTL_NM FROM JRBA_DTL_C WHERE RPT_GJDT = IM.RPT_GJDT AND GRP_CD = IM.CNCT_JIPYO_C_I AND DTL_CD = IA.IN_V) WHEN LENGTH(IA.JIPYO_IDX) = 11 THEN IC.IN_V ELSE IC.IN_V END) AS IN_V , IA.GRP_AVG_PNT , IA.RANK , IA.RPT_PNT , IA.RPT_GJDT FROM JRBA_FIU_JIPYO_V IA INNER JOIN V_GJDT IB ON IA.RPT_GJDT = IB.RPT_GJDT3 INNER JOIN V_SUMMARY_IN_V IC ON IA.RPT_GJDT = IC.RPT_GJDT AND SUBSTR(IA.JIPYO_IDX,1,10) = IC.JIPYO_IDX INNER JOIN JRBA_JIPYO_M IM ON IA.RPT_GJDT = IM.RPT_GJDT AND IA.JIPYO_IDX = IM.JIPYO_IDX LEFT JOIN JRBA_DTL_C DT_CD ON IA.RPT_GJDT = DT_CD.RPT_GJDT AND IA.JIPYO_IDX = DT_CD.DTL_CD AND DT_CD.GRP_CD = 'A999' ) BF_2ROUND ON A.JIPYO_IDX = BF_2ROUND.JIPYO_IDX LEFT JOIN JRBA_DTL_C CD01 ON A.RPT_GJDT = CD01.RPT_GJDT AND CD01.GRP_CD = 'A001' AND A.JIPYO_C = CD01.DTL_CD LEFT JOIN JRBA_DTL_C CD02 ON A.RPT_GJDT = CD02.RPT_GJDT AND CD02.GRP_CD = 'A002' AND A.RSK_CATG = CD02.DTL_CD LEFT JOIN JRBA_DTL_C CD03 ON A.RPT_GJDT = CD03.RPT_GJDT AND CD03.GRP_CD = 'A003' AND A.RSK_FAC = CD03.DTL_CD LEFT JOIN JRBA_DTL_C CD04 ON A.RPT_GJDT = CD04.RPT_GJDT AND CD04.GRP_CD = 'A004' AND A.RSK_CATG = CD04.DTL_CD LEFT JOIN JRBA_DTL_C CD05 ON A.RPT_GJDT = CD05.RPT_GJDT AND CD05.GRP_CD = 'A005' AND A.RSK_FAC = CD05.DTL_CD LEFT JOIN JRBA_DTL_C CD06 ON A.RPT_GJDT = CD06.RPT_GJDT AND CD06.GRP_CD = 'A007' AND A.VALT_G = CD06.DTL_CD LEFT JOIN JRBA_DTL_C CD07 ON A.RPT_GJDT = CD07.RPT_GJDT AND CD07.GRP_CD = 'A013' AND A.IN_METH_C = CD07.DTL_CD LEFT JOIN JRBA_RPT_RST_M D ON A.RPT_GJDT = D.RPT_GJDT /* 보고기준일자 */ LEFT JOIN JRBA_DTL_C CD08 ON A.RPT_GJDT = CD08.RPT_GJDT AND CD08.GRP_CD = 'A999' AND A.JIPYO_IDX = CD08.DTL_CD CROSS JOIN V_GJDT B WHERE 1 = 1 AND A.RPT_GJDT = B.RPT_GJDT1
AND A.JIPYO_IDX LIKE '%' || #{JIPYO_IDX, jdbcType=VARCHAR} || '%'
AND A.JIPYO_NM LIKE '%' || #{JIPYO_NM, jdbcType=VARCHAR} || '%'
AND A.JIPYO_C = #{JIPYO_C,jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG,jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC,jdbcType=VARCHAR}
AND ( A.JIPYO_C = 'I' OR (A.JIPYO_C = 'O' AND LENGTH(A.JIPYO_IDX) = 10) OR (A.JIPYO_C = 'O' AND LENGTH(A.JIPYO_IDX) = 11 AND SUBSTR(A.JIPYO_IDX,11,1) = '1' ) ) ORDER BY A.JIPYO_IDX ASC

WITH V_GJDT AS ( SELECT MAX(CASE WHEN SNO = 1 THEN BB.RPT_GJDT END) AS RPT_GJDT1, MAX(CASE WHEN SNO = 2 THEN BB.RPT_GJDT END) AS RPT_GJDT2, MAX(CASE WHEN SNO = 3 THEN BB.RPT_GJDT END) AS RPT_GJDT3 FROM ( SELECT RPT_GJDT , ROW_NUMBER() OVER (ORDER BY AA.RPT_GJDT DESC) AS SNO FROM JRBA_RPT_BAS_M AA
WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR} ) BB WHERE SNO < 4
) SELECT B.RPT_GJDT1 AS RPT_GJDT1 , NVL(( SELECT RPT_PNT FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT = B.RPT_GJDT1 AND JIPYO_IDX LIKE #{JIPYO_IDX}||'%' AND ( SUBSTR(JIPYO_IDX,1,1) = 'I' OR (SUBSTR(JIPYO_IDX,1,1) = 'O' AND LENGTH(JIPYO_IDX) = 10) OR (SUBSTR(JIPYO_IDX,1,1) = 'O' AND LENGTH(JIPYO_IDX) = 11 AND SUBSTR(JIPYO_IDX,11,1) = '1' ) ) ),0) AS SCORE1 , B.RPT_GJDT2 AS RPT_GJDT2 , NVL(( SELECT RPT_PNT FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT = B.RPT_GJDT2 AND JIPYO_IDX LIKE #{JIPYO_IDX}||'%' AND ( SUBSTR(JIPYO_IDX,1,1) = 'I' OR (SUBSTR(JIPYO_IDX,1,1) = 'O' AND LENGTH(JIPYO_IDX) = 10) OR (SUBSTR(JIPYO_IDX,1,1) = 'O' AND LENGTH(JIPYO_IDX) = 11 AND SUBSTR(JIPYO_IDX,11,1) = '1' ) ) ),0) AS SCORE2 , B.RPT_GJDT3 AS RPT_GJDT3 , NVL(( SELECT RPT_PNT FROM JRBA_FIU_JIPYO_V WHERE RPT_GJDT = B.RPT_GJDT3 AND JIPYO_IDX LIKE #{JIPYO_IDX}||'%' AND ( SUBSTR(JIPYO_IDX,1,1) = 'I' OR (SUBSTR(JIPYO_IDX,1,1) = 'O' AND LENGTH(JIPYO_IDX) = 10) OR (SUBSTR(JIPYO_IDX,1,1) = 'O' AND LENGTH(JIPYO_IDX) = 11 AND SUBSTR(JIPYO_IDX,11,1) = '1' ) ) ),0) AS SCORE3 FROM JRBA_JIPYO_M A, V_GJDT B WHERE A.RPT_GJDT = B.RPT_GJDT1 AND A.JIPYO_IDX LIKE #{JIPYO_IDX}||'%' AND ( A.JIPYO_C = 'I' OR (A.JIPYO_C = 'O' AND LENGTH(A.JIPYO_IDX) = 10) OR (A.JIPYO_C = 'O' AND LENGTH(A.JIPYO_IDX) = 11 AND SUBSTR(A.JIPYO_IDX,11,1) = '1' ) ) ORDER BY A.JIPYO_IDX

SELECT DTL_C 	AS CD,
	   DTL_C_NM AS CD_NM,
	   GRP_C 	AS GRP_CD
  FROM SRBA_DTL_C
 WHERE USYN = 1

   AND GRP_C = #{GRP_C , jdbcType=VARCHAR}


   AND HGRK_GRP_C = #{HGRK_GRP_C , jdbcType=VARCHAR}


   AND HGRK_DTL_C = #{HGRK_DTL_C , jdbcType=VARCHAR}

ORDER BY DTL_C , SNO

SELECT DTL_CD AS CD
     , DTL_NM AS CD_NM
     , GRP_CD AS GRP_CD
  FROM JRBA_DTL_C
 WHERE USYN = 1



   AND RPT_GJDT = ( SELECT MAX(RPT_GJDT) AS RPT_GJDT
                      FROM JRBA_DTL_C
                  )


   AND RPT_GJDT = #{RPT_GJDT , jdbcType=VARCHAR}




	AND GRP_CD = #{GRP_CD, jdbcType=VARCHAR}


	AND HRNK_RBA_RSK_C = #{HRNK_RBA_RSK_C, jdbcType=VARCHAR}


	AND HRNK_RBA_RSK_C_V = #{HRNK_RBA_RSK_C_V, jdbcType=VARCHAR}

ORDER BY SNO

