	UPDATE JRBA_RPT_RST_M SET FIU_RPT_GJDT  = #{FIU_RPT_GJDT}
	                        , ATTCH_FILE_NO = #{ATTCH_FILE_NO}
     WHERE RPT_GJDT = #{RPT_GJDT}

mapper.select:
	WITH V_GJDT AS ( SELECT MAX(DECODE (SNO,1, BB.RPT_GJDT)) AS RPT_GJDT1
	                      , MAX(DECODE (SNO,2, BB.RPT_GJDT)) AS RPT_GJDT2
	                      , MAX(DECODE (SNO,3, BB.RPT_GJDT)) AS RPT_GJDT3
	                   FROM ( SELECT RPT_GJDT
	                               , ROW_NUMBER() over (order by AA.RPT_GJDT DESC )  AS SNO
	                            FROM JRBA_RPT_BAS_M AA

	                           WHERE RPT_GJDT <= #{RPT_GJDT,jdbcType=VARCHAR}
	                        ) BB
	                  WHERE SNO < 4

	)
	SELECT B.RPT_GJDT1 AS RPT_GJDT1
	     , NVL(( SELECT IN_V
	               FROM JRBA_JIPYO_V
	              WHERE RPT_GJDT=B.RPT_GJDT1
	                AND JIPYO_IDX=#{JIPYO_IDX}
	           ),0) AS SCORE1
         , B.RPT_GJDT2 AS RPT_GJDT2
         , NVL(( SELECT IN_V
                   FROM JRBA_JIPYO_V
                  WHERE RPT_GJDT=B.RPT_GJDT2
                    AND JIPYO_IDX=#{JIPYO_IDX}
               ),0) AS SCORE2
         , B.RPT_GJDT3 AS RPT_GJDT3
         , NVL(( SELECT IN_V
                   FROM JRBA_JIPYO_V
                  WHERE RPT_GJDT=B.RPT_GJDT3
                    AND JIPYO_IDX=#{JIPYO_IDX}
               ),0) AS SCORE3
      FROM JRBA_JIPYO_M A, V_GJDT B
     WHERE A.RPT_GJDT  = B.RPT_GJDT1
       AND A.JIPYO_IDX = #{JIPYO_IDX}
     ORDER BY A.JIPYO_IDX

mapper.update:
MERGE INTO JRBA_FIU_JIPYO_V A
  USING DUAL
  ON ( A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR} AND A.JIPYO_IDX =  #{JIPYO_IDX, jdbcType=VARCHAR} )
WHEN MATCHED THEN
	UPDATE SET
	       RPT_PNT  		= #{RPT_PNT, jdbcType=VARCHAR}
	       ,GRP_AVG_PNT  	= #{GRP_AVG_PNT, jdbcType=VARCHAR}
	       ,GRP_MAX_PNT  	= #{GRP_MAX_PNT, jdbcType=VARCHAR}
	       ,GRP_MIN_PNT  	= #{GRP_MIN_PNT, jdbcType=VARCHAR}
	       ,RANK  			= #{RANK, jdbcType=VARCHAR}
           ,CHG_DT 	 		= TO_CHAR(SYSDATE,'YYYYMMDD')
           ,CHG_TIME 		= TO_CHAR(SYSDATE,'HH24MISS')
           ,CHG_OP_JKW_NO 	= #{DR_OP_JKW_NO, jdbcType=VARCHAR}
WHEN NOT MATCHED THEN
	INSERT
	    (
	    RPT_GJDT
	    ,JIPYO_IDX
	    ,IN_V
	    ,RPT_PNT
	    ,ITEM_S_C
	    ,GRP_AVG_PNT
	    ,GRP_MAX_PNT
	    ,GRP_MIN_PNT
	    ,RANK
	    ,DR_DT
	    ,DR_TIME
	    ,DR_OP_JKW_NO
	    ,CHG_DT
	    ,CHG_TIME
	    ,CHG_OP_JKW_NO
	    )
	VALUES
	    (
	    #{RPT_GJDT, jdbcType=VARCHAR}
	    ,#{JIPYO_IDX, jdbcType=VARCHAR}
	    ,#{IN_V, jdbcType=VARCHAR}
	    ,#{RPT_PNT, jdbcType=VARCHAR}
	    ,#{ITEM_S_C, jdbcType=VARCHAR}
	    ,#{GRP_AVG_PNT, jdbcType=VARCHAR}
  		,#{GRP_MAX_PNT, jdbcType=VARCHAR}
  		,#{GRP_MIN_PNT, jdbcType=VARCHAR}
  		,#{RANK, jdbcType=VARCHAR}
  	    ,TO_CHAR(SYSDATE,'YYYYMMDD')
	    ,TO_CHAR(SYSDATE,'HH24MISS')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    ,TO_CHAR(SYSDATE,'YYYYMMDD')
	    ,TO_CHAR(SYSDATE,'HH24MISS')
	    ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
	    )
